  "game_complete": false,
  "game_ending": ""
}

=== TURN 1 ===
{
  "turn": 1,
  "scene_title": "Mill at the River Bend",
  "narration": "Kael shoulders his pack and moves down the muddy river path toward the mill. Lyra lifts her lantern and follows along the bank with quick steps. Kael steps onto the worn planks of the mill's approach and checks the sluice from above. Lyra crouches and sweeps her lantern across the wooden gate and the waterline for signs of rot.\n\nLyra pushes at the sluice and finds it jammed by a wet, black mat of Hollowborn filaments. Kael charges in headfirst and throws his shoulder against the rotten crossbeam. Kael snaps the timber and forces the gate open; water surges through with a harsh roar. Lyra searches for something useful and finds a rusted toolbox lodged behind a stone. Lyra lifts a tar-soaked rag and pulls a flint from the toolbox. Kael stuffs the rag into the worst of the filaments and holds it tight. Lyra strikes the flint and sparks catch the rag. The flames eat the filaments and blister the contaminated wood. Kael drags a plank over the gap and wedges it to slow the flow. Lyra watches smoke curl up and then points upstream at a pale, swollen bulb clinging to the weir; the bulb pulses and releases a fine cloud of motes drifting toward the reservoir.",
  "dialogue": [
    {
      "speaker": "Kael",
      "line": "Stand clear."
    },
    {
      "speaker": "Lyra",
      "line": "This will scorch them."
    }
  ],
  "consequences": "The sluice gate opens and the immediate Hollowborn mat is burned and wedged. Water flows again and the downstream reservoir gains temporary protection. Lyra now has tar and flint. Kael has a singed sleeve and a makeshift plank seal that will hold for now. A new Hollowborn structure upstream emits airborne motes heading for the reservoir.",
  "next_prompt": "Move upstream to the weir and examine the swollen bulb before its motes reach the reservoir.",
  "memory_patch": {
    "sluice_status": "opened and partially sealed with a plank after burning Hollowborn mat",
    "found_items": ["tar-soaked rag", "flint (from toolbox)"],
    "character_statuses": {
      "Kael": "sleeve singed, at mill sluice, carrying plank",
      "Lyra": "hands sooty, holds flint and rag, found tar and toolbox"
    },
    "new_enemy_feature": "pale swollen bulb on upstream weir releasing airborne motes"
  },
  "character_updates": [
    {
      "name": "Kael",
      "position": "mill sluice, river bend",
      "status": "sleeve singed, established temporary plank seal",
      "notes": "Used brute force to free gate"
    },
    {
      "name": "Lyra",
      "position": "mill sluice, river bend",
      "status": "hands sooty, holds flint and tar rag",
      "notes": "Located toolbox and ignited filaments"
    }
  ],
  "open_threads": [
    "Investigate the swollen bulb on the upstream weir",
    "Determine whether airborne motes can infect the reservoir",
    "Assess the reservoir's contamination level downstream",
    "Find a lasting way to seal or destroy Hollowborn in the weir"
  ],
  "continuity_notes": "Next turn must move upstream to the weir. The new encounter should deal with the swollen bulb and airborne motes. Do not revisit the same sluice incident.",
  "location_change": "From Briarfall square to mill sluice at river bend. Next: upstream weir.",
  "game_complete": false,
  "game_ending": ""
}

=== TURN 2 ===
{
  "turn": 2,
  "scene_title": "Weir Above the Mill",
  "narration": "Kael lifts the singed plank. Kael moves up the riverbank toward the weir gates. Lyra follows. Lyra holds the brass lantern over the churned water.\n\nKael stops. Kael points at the swollen bulb pulsing on the upstream face of the weir. Lyra crouches. Lyra studies the bulb. Kael says, \"I'll draw their breath away.\" Kael slams the plank onto the water to make a hollow thud. Kael kicks a loose stone into the current. Lyra intones an old river rhyme in a low voice. The bulb's pores tighten. A cloud of motes condenses. The cloud falls. Kael slides the plank beneath the falling cloud. Kael traps the motes in the eddy with the plank. Lyra watches. Lyra watches the motes wash onto the weir stones. Lyra watches them break apart. Kael pries at the bulb's base. Kael finds a seam under the stone. Lyra reaches into the seam. Lyra pulls free a string of smaller nodules. Kael inspects a nodule. Kael finds pale sap beading at its tip. Kael tosses the nodule into a side pool away from the reservoir. Lyra says, \"They hide deeper beneath the weir.\" A stone shifts. A narrow tunnel opens under the weir.",
  "dialogue": [
    {
      "speaker": "Kael",
      "line": "I'll draw their breath away."
    },
    {
      "speaker": "Lyra",
      "line": "They hide deeper beneath the weir."
    }
  ],
  "consequences": "The immediate stream of airborne motes stops before reaching the reservoir. Kael used the plank to trap falling motes and prevented a direct contamination. Lyra's incantation caused the bulb's pores to tighten and forced motes to condense. The party recovered a string of smaller nodules and identified pale sap as a spore medium. A narrow tunnel under the weir has opened and reveals more hidden clusters that must be cleared.",
  "next_prompt": "Enter the newly revealed tunnel beneath the weir and inspect the cluster nests hidden in the dark channel before they flush into the reservoir.",
  "memory_patch": {
    "location": "upstream weir, river bend",
    "weir_status": "primary bulb contracted; motes condensed and neutralized at surface; smaller nodules recovered",
    "discovered": [
      "string of smaller nodules under the weir",
      "pale sap on nodules (spore medium)",
      "narrow tunnel beneath the weir"
    ],
    "actions_taken": [
      "Kael created a physical distraction with the plank and trapped motes in an eddy",
      "Lyra used a river rhyme to force the bulb to constrict"
    ],
    "immediate_threat": "neutralized for now",
    "next_threat": "hidden clusters in tunnel under the weir"
  },
  "character_updates": [
    {
      "name": "Kael",
      "position": "upstream weir",
      "status": "holds singed plank, inspected nodule, ready to enter tunnel",
      "notes": "Created distraction and trapped motes; tested nodule and tossed it into side pool"
    },
    {
      "name": "Lyra",
      "position": "upstream weir",
      "status": "lantern lit, hands muddy, used river rhyme",
      "notes": "Forced bulb to tighten and revealed seam with nodules"
    }
  ],
  "open_threads": [
    "Investigate the narrow tunnel beneath the weir",
    "Clear the deeper clusters and remove their sap medium",
    "Assess reservoir for any remaining contamination downstream",
    "Find a lasting method to seal or destroy hidden Hollowborn nests"
  ],
  "continuity_notes": "Next turn must move into the tunnel under the weir. The new encounter should be a distinct problem (e.g., nest chamber, trapped current, or structural collapse) and resolve by end of that turn.",
  "location_change": "From mill sluice to upstream weir. Next location: tunnel under the weir.",
  "game_complete": false,
  "game_ending": ""
}

=== TURN 3 ===
{
  "turn": 3,
  "scene_title": "Tunnel Beneath the Weir",
  "narration": "Kael wedges the singed plank under his arm and steps into the dark throat of the tunnel. Lyra follows a pace behind and lifts the brass lantern into the low arch. Kael feels the cold trickle along the floor and moves toward the narrowing channel.\n\nKael halts at the first swell of sap. Kael braces his feet against the stone. Kael jams the plank into the channel to slow the surge. Lyra crouches and sets the lantern down. Lyra runs her fingers along the seam of the wall. Lyra finds a hairline fissure that breathes a draught. Kael digs his heels deeper. Kael keeps the plank steady against the pushed nodules. Lyra widens the fissure with a hooked nail from the toolbox. Lyra forces a thin stream into a side wash where the nodules can sink harmlessly. Kael scoops a fallen nodule and holds it away from the current. Lyra strikes the flint and cauters the bead of sap on the nodule with the tar rag.\n\nKael says, \"Hold fast.\" Lyra says, \"A narrow drain leads to a settling pool.\" The diverted flow takes the nodules into the wash. The tunnel clears. Lyra scrapes mud from a carved stone in the floor and reveals a rusted wheel set into the rock.",
  "dialogue": [
    {
      "speaker": "Kael",
      "line": "Hold fast."
    },
    {
      "speaker": "Lyra",
      "line": "A narrow drain leads to a settling pool."
    }
  ],
  "consequences": "The immediate surge of sap and motes was diverted into a side wash and neutralized by cauterizing recovered nodules. Kael's plank prevented a sudden flush into the reservoir. Lyra's hidden path rerouted contaminated material away from the main current. A carved stone wheel now lies exposed in the tunnel floor, suggesting a deeper mechanism or chamber beneath the weir.",
  "next_prompt": "Investigate the carved stone wheel and determine whether it opens a deeper culvert or triggers another hazard beneath the weir.",
  "memory_patch": {
    "location": "tunnel beneath the weir",
    "actions_taken": [
      "Kael used plank to hold back surge and prevent nodules from flushing into reservoir",
      "Lyra found and widened a hidden drain to divert contaminated nodules",
      "Lyra cauterized a nodule with tar and flint"
    ],
    "found_items": ["hidden fissure/drain", "carved stone wheel in tunnel floor"],
    "tunnel_status": "contaminated flow diverted; immediate threat neutralized",
    "next_discovery": "stone wheel set into floor may connect to deeper culvert"
  },
  "character_updates": [
    {
      "name": "Kael",
      "position": "inside tunnel under weir",
      "status": "holding plank to steady flow, arms strained",
      "notes": "Prevented nodules from entering main current"
    },
    {
      "name": "Lyra",
      "position": "ahead in tunnel",
      "status": "lantern low, hands smeared with sap, found hidden drain and exposed stone wheel",
      "notes": "Diverted contamination and cauterized nodules"
    }
  ],
  "open_threads": [
    "Determine function and danger of the carved stone wheel",
    "Explore deeper culvert or chamber beneath the weir",
    "Confirm reservoir remains uncontaminated downstream",
    "Locate other hidden Hollowborn clusters beyond this tunnel"
  ],
  "continuity_notes": "Next turn must move into the deeper chamber or operate the stone wheel. The new encounter should be distinct from the tunnel surge (e.g., trapped mechanism, a sealed chamber, or a nest chamber) and resolve by the end of that turn.",
  "location_change": "From upstream weir tunnel to deeper chamber beneath the weir (stone wheel revealed).",
  "game_complete": false,
  "game_ending": ""
}
